// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  let conversation = item.json.output[0].content[0].text.conversations
  item.json.conversation_string = JSON.stringify(conversation);
}

return $input.all();

const base = 5;          // starting point
const max = 40;          // max warm-up per inbox
const growth = 2;        // +2 per day

const todayCount = Math.min(
  $json.warmup_sent_today + growth,
  max
);

return [{
  json: {
    ...$json,
    warmup_target_today: todayCount
  }
}]

const sender = $("Calculate daily warmup target").all()[0].json.email;
const target = $("Calculate daily warmup target").all()[0].json.warmup_target_today;

// Incoming items from Data Tables (other inboxes)
const recipients = $("Get recipient inboxes (excluding sender)").all().map(i => i.json);

// Shuffle array
for (let i = recipients.length - 1; i > 0; i--) {
  const j = Math.floor(Math.random() * (i + 1));
  [recipients[i], recipients[j]] = [recipients[j], recipients[i]];
}

// Pick target count, or all if fewer
const selected = recipients.slice(0, target);

return selected.map(r => ({
  json: {
    inboxA: sender,
    inboxB: r.email,
    target
  }
}));

let items = $input.all()
let allmessages = []
for (let i = 0; i < items.length; i++) {
  const messages = JSON.parse(items[i].json.messages || "[]");
  allmessages.push({
    conversation_id: items[i].json.id,
    message: messages
  })
}
// return messages.map(m => ({ json: m }));
return allmessages

const message = $input.item.json.message;
let conversation_id = $input.item.json.conversation_id
let inboxA = $input.item.json.inboxA;
let inboxB = $input.item.json.inboxB;

let conversations = [];
const now = new Date();

for (let i = 0; i < message.length; i++) {

  // sender / receiver
  const isA = message[i].sender === "A";
  const sender_inbox = isA ? inboxA : inboxB;
  const receiver_inbox = isA ? inboxB : inboxA;

  // Calculate scheduled_date = today + i days
  const scheduledDateObj = new Date(now);
  scheduledDateObj.setDate(now.getDate() + i);

  const scheduledDate = scheduledDateObj.toISOString().split("T")[0];

  conversations.push({
    sender_inbox,
    receiver_inbox,
    subject: message[i].subject,
    body: message[i].body,
    scheduled_date: scheduledDate,  // ONLY DATE, no time
    scheduled_at: null,             // sender engine assigns actual time later
    sent: false,
    conversation_id,
    conversation_index: i
  });
}

return { conversation: conversations };

let conversationsArray = $input.all()
let conversations = []

for (let i = 0; i < conversationsArray.length; i++) {
  for (let j = 0; j < conversationsArray[i].json.conversation.length; j++) {
  conversations.push(conversationsArray[i].json.conversation[j])
  }
}

return conversations;

const startHour = 8;   // daily window start
const endHour = 22;    // daily window end

function createISTDate(hour, minute = 0) {
  const now = new Date();

  // Convert today's date to IST
  const ist = new Date(
    now.getFullYear(),
    now.getMonth(),
    now.getDate(),
    hour,
    minute,
    0,
    0
  );

  // IST → UTC
  const utc = new Date(ist.getTime() - (5.5 * 60 * 60 * 1000));
  return utc;
}

function randomTimeInWindow(startHour, endHour) {
  const now = new Date();

  const start = createISTDate(startHour);
  const end = createISTDate(endHour);

  // Random time between start and end
  const randomMs = start.getTime() + Math.random() * (end.getTime() - start.getTime());

  return new Date(randomMs);
}


// These come from DB fetch via n8n
let warmups = $input.all();  

let updatedRows = [];

for (let item of warmups) {
  let row = item.json;

  // Assign a random timestamp ONLY if it's scheduled for today and not assigned yet
  if (!row.scheduled_at) {
    row.scheduled_at = randomTimeInWindow(startHour, endHour).toISOString();
  }

  updatedRows.push(row);
}

return updatedRows;

const now = new Date();
let due = [];

for (let item of $input.all()) {
  const row = item.json;
  if (row.scheduled_at && new Date(row.scheduled_at) <= now) {
    due.push(row);
  }
}

return due;

